; cc65 runtime
.include "zeropage.inc"
.import push1, pusha0, pushax

; sim65 vectors
.import _write, exit 

; Generated by linker
.import __MAIN_START__, __MAIN_SIZE__
.import __STACKSIZE__

.include "basic.inc"

.segment "STARTUP"

message: .byte "Enter your name: "
message_length = * - message
hello: .byte "Hello, "
hello_length = * - hello

startup:
.export startup
        cld                     ; Clear decimal flag
        ldx     #$FF
        txs                     ; Initialize the stack to $FF
        lda     #<(__MAIN_START__ + __MAIN_SIZE__ + __STACKSIZE__)
        ldx     #>(__MAIN_START__ + __MAIN_SIZE__ + __STACKSIZE__)
        sta     sp
        stx     sp+1            ; Set up C stack

        lda     #<message       ; Load ptr1 with the message pointer
        ldx     #>message
        ldy     #message_length
        jsr     putline         ; Write the message

        jsr     getline         ; Get the user's input
        lda     #<hello         ; Load ptr1 with the hello pointer
        ldx     #>hello
        ldy     #hello_length
        jsr     putline         ; Write "hello"
        jsr     putline_buffer  ; Output name (still in buffer)
        lda     #$0A            ; Linefeed
        jsr     putchar         ; Write linefeed

        ldx     #$00
        lda     #$00
        jmp     exit            ; Return 0 from sim65
